INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-7ec62a85-moex-00112', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-112-e2754278', 'sub-pukao-7ec62a85-04', NULL, 'essay', '甲開車出門吃飯，因為餐廳門口已無停車位停車，甲為貪圖方便，便在餐
廳外違規併排停車。由於正值交通尖峰時段，該處車流量大，騎機車經過
的老翁乙因為可行駛車道狹窄，撞上甲違停的汽車倒地，頭部受傷流血不
止。甲在餐廳內聽到巨響，急忙出來查看，甲雖然認識到老翁傷及頭部流
血不止，不立刻送醫，肯定會喪失性命，但因擔心要負相關的法律責任，
便悶不吭聲地將車開走，逃逸無蹤。現場圍觀民眾以為已經有人報警，便
圍在路旁評論事發經過，乙後來因為未及時送醫，死於流血過多。試問甲
有何刑責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "8f4b9256a909", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "415", "s": "1212", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00113', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-112-e2754278', 'sub-pukao-7ec62a85-04', NULL, 'essay', '甲的鄰居乙為暴發戶，由於乙時常炫富，動不動就將手提包打開，展示隨
身都有數萬元的現金，故頗受鄰里非議。甲因為生意失敗，1萬元的房租
都付不出來，故將歪腦筋動到乙的身上。某夜，甲埋伏在乙家門口，見有
一體型跟乙一般的人出門，甲即上前將其推倒在地，並將其隨身的手提包
搶走。孰料被推倒遭搶之人是乙的窮親戚丙，甲打開手提包只有1千元，
甲用這筆錢跟家人吃了頓飯。試問甲有何刑責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "8f4b9256a909", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "415", "s": "1212", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00114', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-112-e2754278', 'sub-pukao-7ec62a85-04', NULL, 'essay', '大學生甲男跟同宿舍室友乙男同時在追求同班同學丙女，甲為了解情敵
的動態，趁乙上網登入臉書時，在後面偷看並記取其帳號密碼。嗣甲即以
自己之電腦輸入乙臉書帳號密碼後登入，並閱讀乙跟丙之通話紀錄。上開
情形經乙發現後，對甲提出相關告訴。試問甲觸犯刑法上何罪名？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "8f4b9256a909", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "415", "s": "1212", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00115', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-112-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '下列何者非屬成文法法源？', '["議會自律規則", "國際條約", "一般法律原則", "行政規則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "415", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00116', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-112-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於法規命令之訂定與生效，下列敘述何者錯誤？', '["法規命令依法應經上級機關核定者，於核定後始得發布", "法規命令之發布，應刊登於政府公報或新聞紙", "任何人得於公告期間內針對法規命令之草案提出意見", "法規命令乃行政權行使，受司法違憲之審查，惟不受立法權之審查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "415", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00117', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-112-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '下列何者非屬行政程序法明定之一般法律原則？', '["對等互惠原則", "誠實信用原則", "比例原則", "平等原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "415", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00118', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-112-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '行政機關對於法律構成要件之涵攝，除有明顯瑕疵外，行政法院應予尊重之情形，為下列何者？', '["裁量收縮至零", "裁量瑕疵", "判斷餘地", "計畫裁量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "415", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00119', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-112-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於給付行政之敘述，下列何者正確？', '["給付行政全屬公權力之行使，均為公法事件", "農民健康保險之給付事項屬給付行政，為公法事件", "給付行政與干涉行政相同，均受嚴格之法律保留原則所拘束", "金融機構辦理清寒學生助學貸款，屬公法性質之給付行政"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "415", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00120', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-112-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '某公立高中學生無照騎乘機車，受記大過一次之處分。其不服時，依司法院大法官解釋，得提起何種之救濟？', '["得依法提起相應之行政爭訟程序", "因非屬退學或類此之處分，故不得提起救濟", "只得依循校內救濟途徑提起救濟", "應依民事程序請求救濟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "415", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00121', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-112-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於行政法人之概念，下列敘述何者錯誤？', '["行政法人所涉及公權力程度較低", "係為執行特定公共事務，依法律設立之公法人", "行政法人之經費必須全數自籌", "人民對於行政法人所為行政處分不服，應向監督機關提起訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "415", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL)
